RAW_URL="https://raw.githubusercontent.com/cyberpatriotITNH/Universal-Hardening-Script/main/checklist.ps1.sh"; bash -c "INSTALL_PATH=/usr/local/bin/checklist; sudo curl -fsSL \"$RAW_URL\" -o \$INSTALL_PATH && sudo chmod +x \$INSTALL_PATH && grep -qxF \"alias checklist='sudo \$INSTALL_PATH'\" ~/.bashrc || echo \"alias checklist='sudo \$INSTALL_PATH'\" >> ~/.bashrc && echo '✅ Installed checklist at \$INSTALL_PATH. Run with: checklist'" || powershell -NoProfile -Command "\$dest=\"$env:USERPROFILE\\checklist.ps1\"; Invoke-WebRequest -Uri '$RAW_URL' -OutFile \$dest; Set-Alias checklist \$dest; \$profileDir = Split-Path \$PROFILE; if (!(Test-Path \$profileDir)) { New-Item -ItemType Directory -Path \$profileDir -Force | Out-Null }; if (!(Select-String -Path \$PROFILE -Pattern 'Set-Alias checklist')) { Add-Content -Path \$PROFILE -Value \"Set-Alias checklist `\"\$dest`\"\" }; Write-Host '✅ Installed checklist for PowerShell and persisted alias. Run with: checklist'"
